/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements the NotificationAdapter interface with:
 * - Phone number validation
 * - Message formatting (subject + body, truncated to SMS limits)
 * - Priority-based handling
 * - Configurable send behavior (for testing vs production use)
 *
 * In dev/test mode, SMS messages are stored in memory. A production
 * implementation would integrate with an SMS gateway (Twilio, SNS, etc.).
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, NotificationDeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A record of an SMS that was "sent" (logged in dev/test).
 */
export interface SentSms {
  to: string;
  message: string;
  priority: string;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  fromNumber: string;
  maxMessageLength: number;
}

const DEFAULT_CONFIG: SmsAdapterConfig = {
  fromNumber: '+15551234567',
  maxMessageLength: 160,
};

/**
 * Simple phone number validation — requires E.164-like format.
 * Accepts numbers starting with + followed by digits, or plain digit strings
 * of 10+ characters.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+?\d{10,15}$/.test(phone);
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private config: SmsAdapterConfig;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Send a notification via SMS.
   *
   * Validates the recipient phone number, formats the message, and stores it.
   * Returns a delivery result indicating success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    if (!payload.recipient || !isValidPhoneNumber(payload.recipient)) {
      this.logger.error(`Invalid SMS recipient: ${payload.recipient}`);
      return {
        success: false,
        channel: 'sms',
        error: `Invalid phone number: ${payload.recipient}`,
      };
    }

    try {
      const message = this.formatMessage(payload);

      this.logger.info(
        `Sending ${payload.priority}-priority SMS to ${payload.recipient}: ${payload.subject}`,
      );

      const sms: SentSms = {
        to: payload.recipient,
        message,
        priority: payload.priority,
        sentAt: new Date(),
        metadata: payload.metadata,
      };

      this.sentMessages.push(sms);

      return {
        success: true,
        channel: 'sms',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return {
        success: false,
        channel: 'sms',
        error: message,
      };
    }
  }

  /**
   * Format a notification payload into an SMS-friendly message.
   * Combines subject and body, truncating to the configured max length.
   */
  formatMessage(payload: NotificationPayload): string {
    const fullMessage = `${payload.subject}: ${payload.body}`;
    if (fullMessage.length <= this.config.maxMessageLength) {
      return fullMessage;
    }
    return fullMessage.slice(0, this.config.maxMessageLength - 3) + '...';
  }

  /**
   * Get the adapter configuration (read-only copy).
   */
  getConfig(): Readonly<SmsAdapterConfig> {
    return { ...this.config };
  }

  /**
   * Get all sent messages (useful for testing).
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history (useful for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15559876543',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order_confirmation',
    channel: 'sms',
    priority: 'normal',
    metadata: { orderId: 'order-1' },
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('send', () => {
    it('should successfully send to a valid phone number', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.error).toBeUndefined();
    });

    it('should store sent message with correct fields', async () => {
      await adapter.send(makePayload());

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15559876543');
      expect(messages[0]?.message).toContain('Test Subject');
      expect(messages[0]?.message).toContain('Test body content');
      expect(messages[0]?.priority).toBe('normal');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
      expect(messages[0]?.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should fail for invalid phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-number' }));

      expect(result.success).toBe(false);
      expect(result.channel).toBe('sms');
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for too-short phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '+12345' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should accept phone number without + prefix', async () => {
      const result = await adapter.send(makePayload({ recipient: '15559876543' }));

      expect(result.success).toBe(true);
    });

    it('should not store message on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));

      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ recipient: '+15559876543' }));
      await adapter.send(makePayload({ recipient: '+15551112222' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should include priority in sent message', async () => {
      await adapter.send(makePayload({ priority: 'high' }));

      expect(adapter.getSentMessages()[0]?.priority).toBe('high');
    });
  });

  describe('message formatting', () => {
    it('should combine subject and body', () => {
      const message = adapter.formatMessage(makePayload());

      expect(message).toBe('Test Subject: Test body content');
    });

    it('should truncate long messages to max length', () => {
      const longBody = 'A'.repeat(200);
      const message = adapter.formatMessage(makePayload({ body: longBody }));

      expect(message.length).toBe(160);
      expect(message).toMatch(/\.\.\.$/);
    });

    it('should not truncate messages within limit', () => {
      const message = adapter.formatMessage(makePayload({ subject: 'Hi', body: 'Short' }));

      expect(message).toBe('Hi: Short');
      expect(message).not.toContain('...');
    });

    it('should respect custom max message length', () => {
      const custom = new SmsAdapter({ maxMessageLength: 50 });
      const message = custom.formatMessage(makePayload({ body: 'A'.repeat(100) }));

      expect(message.length).toBe(50);
      expect(message).toMatch(/\.\.\.$/);
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const config = adapter.getConfig();

      expect(config.fromNumber).toBe('+15551234567');
      expect(config.maxMessageLength).toBe(160);
    });

    it('should accept custom config', () => {
      const custom = new SmsAdapter({
        fromNumber: '+15550001111',
        maxMessageLength: 320,
      });

      const config = custom.getConfig();
      expect(config.fromNumber).toBe('+15550001111');
      expect(config.maxMessageLength).toBe(320);
    });

    it('should return defensive copy of config', () => {
      const config1 = adapter.getConfig();
      const config2 = adapter.getConfig();
      expect(config1).not.toBe(config2);
      expect(config1).toEqual(config2);
    });
  });

  describe('message management', () => {
    it('should return defensive copy of sent messages', async () => {
      await adapter.send(makePayload());

      const messages1 = adapter.getSentMessages();
      const messages2 = adapter.getSentMessages();
      expect(messages1).not.toBe(messages2);
      expect(messages1).toEqual(messages2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();

      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
});

